function collectMarketSelectableEquipmentItems(slots, backpack, listedSourceIds) {
  if (!backpack?.publicKey || !equippedPlayerProfileStatus?.equipment?.length) return [];
  const defaultKey = "11111111111111111111111111111111";
  const slotByItemPda = new Map(
    slots
      .filter((slot) => slot?.itemPda && slot.itemPda !== defaultKey)
      .map((slot) => [slot.itemPda, slot]),
  );
  return equippedPlayerProfileStatus.equipment.flatMap((itemPda, equipmentSlotIndex) => {
    if (!itemPda || itemPda === defaultKey) return [];
    const slot = slotByItemPda.get(itemPda);
    if (!slot) return [];
    const id = marketEquipmentSourceItemId(equipmentSlotIndex, itemPda, backpack.publicKey);
    const sourceIds = [
      id,
      marketEquipmentSourceItemId(equipmentSlotIndex, itemPda),
      marketItemPdaSourceItemId(itemPda),
      slot.sourceItemId,
      slot.legacySourceItemId,
    ].filter(Boolean);
    if (sourceIds.some((sourceId) => listedSourceIds.has(sourceId))) return [];
    const category = marketCategoryForBackpackSlot(slot);
    return [{
      id,
      sourceItemIds: Array.from(new Set(sourceIds)),
      slotIndex: equipmentSlotIndex,
      backpackSlotIndex: slot.chainIndex,
      source: "equipment",
      backpack: backpack.publicKey,
      name: backpackSlotDisplayName(slot),
      meta: `${marketEquipmentSlotLabel(equipmentSlotIndex)} · ${slot.meta?.source ?? gameText("main.backpack.unknownSource", "Unknown source")}`,
      category,
      iconType: marketIconTypeForCategory(category),
      slot,
    }];
  });
}

